const exec = $input.first().json;
if (!exec.success) {
  return [{ json: { toon: `error: ${exec.error || "unknown"}` } }];
}

const raw = exec.output || "";
const lines = raw.split("\n");

// Noise lines from `acli jira auth switch` output that must not pollute the ticket TOON
const NOISE_KEYS = new Set([
  "authenticated_site",
  "switched_to_account",
  "authentication_type",
  "email",
  "token",
  "site"
]);
const NOISE_PREFIXES = ["✓", "✗", "⚠"];

const data = {};
for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;
  if (NOISE_PREFIXES.some(p => trimmed.startsWith(p))) continue;

  const m = line.match(/^([A-Za-z][A-Za-z0-9_ ]*)\s*:\s*(.+)$/);
  if (!m) continue;

  const key = m[1].trim().toLowerCase().replace(/\s+/g, "_");
  if (NOISE_KEYS.has(key)) continue;

  data[key] = m[2].trim();
}

const toonLines = [];
for (const [k, v] of Object.entries(data)) {
  const needsQuotes = /[,:\n]/.test(v);
  toonLines.push(`${k}: ${needsQuotes ? `"${v.replace(/"/g, "\\\"")}"` : v}`);
}

if (toonLines.length === 0) {
  toonLines.push(`raw: "${raw.replace(/"/g, "\\\"").replace(/\n/g, "\\n")}"`);
}

return [{ json: { toon: toonLines.join("\n") } }];
